async function processMessage(message) {
  let parsedMessage;
  
  try {
    parsedMessage = JSON.parse(message.content.toString());
  } catch (error) {
    console.error('Invalid JSON message:', error);
    await logEvent('parse_error', { raw: message.content.toString() }, 'failed', error.message);
    return { success: false, error: 'Invalid JSON' };
  }
  
  const { type, payload } = parsedMessage;
  
  try {
    validateMessageType(type);
    validatePayload(payload);
    
    let result;
    
    switch (type) {
      case 'user.created':
        result = await executeInsertQuery('users', payload);
        await logEvent(type, payload, 'success');
        break;
        
      case 'user.updated':
        if (!payload.conditions || !payload.data) {
          throw new Error('Update requires conditions and data');
        }
        result = await executeUpdateQuery('users', payload.data, payload.conditions);
        await logEvent(type, payload, 'success');
        break;
        
      case 'user.deleted':
        if (!payload.conditions) {
          throw new Error('Delete requires conditions');
        }
        result = await executeDeleteQuery('users', payload.conditions);
        await logEvent(type, payload, 'success');
        break;
        
      case 'order.created':
        result = await executeInsertQuery('orders', payload);
        await logEvent(type, payload, 'success');
        break;
        
      case 'order.updated':
        if (!payload.conditions || !payload.data) {
          throw new Error('Update requires conditions and data');
        }
        result = await executeUpdateQuery('orders', payload.data, payload.conditions);
        await logEvent(type, payload, 'success');
        break;
        
      case 'system.backup':
        result = await executeSystemCommand('backup', payload);
        await logEvent(type, payload, result.success ? 'success' : 'failed', result.error);
        break;
        
      case 'system.cleanup':
        result = await executeSystemCommand('cleanup', payload);
        await logEvent(type, payload, result.success ? 'success' : 'failed', result.error);
        break;
        
      default:
        throw new Error(`Unhandled message type: ${type}`);
    }
    
    console.log(`Processed message type: ${type}`, result);
    return { success: true, result };
    
  } catch (error) {
    console.error(`Error processing message type ${type}:`, error);
    await logEvent(type, payload, 'failed', error.message);
    return { success: false, error: error.message };
  }
}

async function startConsumer() {
  let connection;
  let channel;
  
  try {
    connection = await amqp.connect(RABBITMQ_URL);
    channel = await connection.createChannel();
    
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-max-length': 10000,
        'x-message-ttl': 86400000
      }
    });
    
    await channel.prefetch(10);
    
    console.log(`Waiting for messages in queue: ${QUEUE_NAME}`);
    
    channel.consume(QUEUE_NAME, async (message) => {
      if (message !== null) {
        try {
          const result = await processMessage(message);
          
          if (result.success) {
            channel.ack(message);
          } else {
            channel.nack(message, false, false);
          }
        } catch (error) {
          console.error('Unexpected error processing message:', error);
          channel.nack(message, false, false);
        }
      }
    }, {
      noAck: false
    });
    
    process.on('SIGINT', async () => {
      console.log('Shutting down gracefully...');
      await channel.close();
      await connection.close();
      await pool.end();
      process.exit(0);
    });
    
  } catch (error) {
    console.error('Failed to start consumer:', error);
    if (channel) await channel.close();
    if (connection) await connection.close();
    await pool.end();
    process.exit(1);
  }
}

